esbuild limitations: no `emitDecoratorMetadata` (use SWC for that), no const enum across files, no declaration (.d.ts) output. Pair with `tsc --emitDeclarationOnly` for types.

Memory leaks in Node.js usually come from event listeners, closures, caches, or global state. Heap snapshots pinpoint what's retained.

```typescript
// Trigger heap snapshot programmatically
import v8 from 'node:v8';
import { writeFileSync } from 'node:fs';

function takeHeapSnapshot() {
  const snapshotStream = v8.writeHeapSnapshot();
  console.log(`Heap snapshot written to ${snapshotStream}`);
}

// Take snapshot on signal
process.on('SIGUSR2', takeHeapSnapshot);
// Then: kill -USR2 <pid>

// Expose via HTTP endpoint (development only!)
import { createServer } from 'node:http';
const server = createServer((req, res) => {
  if (req.url === '/__heap') {
    const file = v8.writeHeapSnapshot();
    res.end(`Snapshot: ${file}`);
  }
});
```

```bash
# CLI approach
node --inspect src/index.js
# Open chrome://inspect → Memory tab → Take heap snapshot

# Compare two snapshots to find growth:
# 1. Take snapshot at baseline
# 2. Run the suspected leaky operation
# 3. Take another snapshot
# 4. Use "Comparison" view to see what objects grew

# Quick check: process.memoryUsage()
setInterval(() => {
  const mem = process.memoryUsage();
  console.log(`RSS: ${(mem.rss / 1024 / 1024).toFixed(1)}MB, Heap: ${(mem.heapUsed / 1024 / 1024).toFixed(1)}MB`);
}, 10000);
```

CPU profiles reveal which functions consume the most time. Use V8's built-in profiler or the inspector protocol.

```bash
# Method 1: --prof flag (V8 tick profiler)
node --prof src/index.js
# Generates isolate-*.log
node --prof-process isolate-*.log > profile.txt
# Look for [Summary] section → ticks breakdown

# Method 2: --cpu-prof (outputs .cpuprofile)
node --cpu-prof --cpu-prof-dir=./profiles src/index.js
# Load the .cpuprofile in Chrome DevTools → Performance tab

# Method 3: Inspector API (profile specific code sections)
```

```typescript
import { Session } from 'node:inspector/promises';

const session = new Session();
session.connect();

async function profileFunction<T>(fn: () => Promise<T>): Promise<T> {
  await session.post('Profiler.enable');
  await session.post('Profiler.start');

  const result = await fn();

  const { profile } = await session.post('Profiler.stop');
  const { writeFile } = await import('node:fs/promises');
  await writeFile('profile.cpuprofile', JSON.stringify(profile));
  console.log('Profile saved to profile.cpuprofile');

  return result;
}

// Usage
await profileFunction(async () => {
  await heavyComputation();
});
```

Open `.cpuprofile` files in Chrome DevTools (Performance tab → Load profile) or VS Code ("Flame Chart" extension). Look for wide bars — those are the slow functions.

npm workspaces (npm 7+) manage multiple packages in one repo with shared dependencies and cross-references.

```jsonc
// Root package.json
{
  "name": "my-monorepo",
  "private": true,
  "workspaces": ["packages/*", "apps/*"]
}

// packages/shared/package.json
{
  "name": "@repo/shared",
  "version": "0.0.0",
  "main": "./dist/index.js",
  "types": "./dist/index.d.ts",
  "scripts": { "build": "tsup src/index.ts --format esm,cjs --dts" }
}

// apps/api/package.json
{
  "name": "@repo/api",
  "dependencies": {
    "@repo/shared": "*"  // References the workspace package
  }
}
```

```bash
