}
```

```typescript
// When authoring a library, be generous with peer dep ranges:
{
  "peerDependencies": {
    "react": "^17.0.0 || ^18.0.0 || ^19.0.0" // Wide range
  },
  "peerDependenciesMeta": {
    "react": { "optional": true } // Won't error if missing
