```typescript
// Packages that are ESM-only (major versions):
// chalk@5, got@12+, execa@6+, node-fetch@3, p-limit@4+, globby@13+
// nanoid@4+, strip-ansi@7+, ora@7+, figures@6+

// FIX 1: Use dynamic import (works from CJS)
async function main() {
